try {
  const { extracted_text = '' } = ($input.first().json || {});
  if (!extracted_text) throw new Error('No extracted_text provided');

  const io = { inputs: [], outputs: [] };

  // Enhanced regex patterns for HVAC components
  const inputPatterns = [
    /(temperature|pressure|status|setpoint|signal|monitor|sensor|reading|value|feedback)/gi,
    /(outdoor\s+air|return\s+air|supply\s+air|mixed\s+air)\s+(temperature|humidity)/gi,
    /(damper|valve)\s+(position|status)/gi
  ];

  const outputPatterns = [
    /(fan|valve|damper|actuator|pump|heater|cooler)\s*(modulate|run|open|close|shut|start|stop|enable|disable)/gi,
    /(supply|return|exhaust)\s+fan/gi,
    /(heating|cooling)\s+(valve|coil)/gi
  ];

  // Extract inputs
  inputPatterns.forEach(pattern => {
    const matches = extracted_text.match(pattern) || [];
    matches.forEach(m => {
      const clean = m.trim().toLowerCase();
      if (!io.inputs.some(existing => existing.toLowerCase() === clean)) {
        io.inputs.push(m.trim());
      }
    });
  });

  // Extract outputs
  outputPatterns.forEach(pattern => {
    const matches = extracted_text.match(pattern) || [];
    matches.forEach(m => {
      const clean = m.trim().toLowerCase();
      if (!io.outputs.some(existing => existing.toLowerCase() === clean)) {
        io.outputs.push(m.trim());
      }
    });
  });

  return { io_points: io };
} catch(e) {
  return { error: 'Failed to extract I/O points: ' + e.message };
}

try {
  const { extracted_text = '' } = ($input.first().json || {});
  if (!extracted_text) throw new Error('No extracted_text provided');

  const blockKeywords = {
    'Safety/Alarms': /safety|alarm|emergency|trip|fault|error|fail/gi,
    'Scheduling/Modes': /schedule|mode|time|occupied|unoccupied|start|stop/gi,
    'Fan Control': /fan|blower|cfm|airflow|speed/gi,
    'Temperature Control': /temperature|setpoint|heating|cooling|thermostat/gi,
    'Damper Control': /damper|outdoor\s+air|return\s+air|mixed\s+air|economizer/gi,
    'Valve Control': /valve|chilled\s+water|hot\s+water|steam/gi,
    'Pressure Control': /pressure|static|differential/gi
  };

  const blocks = Object.keys(blockKeywords).filter(blockName => {
    return extracted_text.match(blockKeywords[blockName]);
  });

  return { 
    blocks: blocks.length ? blocks : ['General HVAC Sequence'],
    block_details: blocks.length ? blocks.map(b => ({
      name: b,
      keywords_found: extracted_text.match(blockKeywords[b]) || []
    })) : []
  };
} catch(e) {
  return { error: 'Failed to decompose blocks: ' + e.message };
}

try {
  const { blocks = [], io_points = {}, extracted_text = '' } = ($input.first().json || {});
  if (!blocks.length && !io_points.inputs) throw new Error('No blocks or io_points provided');

  const inputs = io_points.inputs || [];
  const outputs = io_points.outputs || [];

  const pseudocode = blocks.map(blockName => {
    let logic = [];

    // Generate context-aware logic based on block type
    switch(blockName.toLowerCase()) {
      case 'safety/alarms':
        logic = [
          'IF safety_condition_violated THEN',
          '  SHUTDOWN all_equipment',
          '  ACTIVATE alarm',
          '  LOG safety_event'
        ];
        break;
      case 'fan control':
        logic = [
          'IF occupied_mode AND temperature_deviation > threshold THEN',
          '  MODULATE fan_speed BASED_ON temperature_error',
          'ELSE',
          '  SET fan_speed TO minimum_ventilation'
        ];
        break;
      case 'temperature control':
        logic = [
          'IF space_temperature < heating_setpoint THEN',
          '  OPEN heating_valve',
          'ELSE IF space_temperature > cooling_setpoint THEN',
          '  OPEN cooling_valve',
          'ELSE',
          '  CLOSE all_valves'
        ];
        break;
      default:
        // Generic logic using available I/O points
        if (inputs.length && outputs.length) {
          logic = [
            `IF ${inputs[0]} meets_condition THEN`,
            `  ACTIVATE ${outputs[0]}`,
            'ELSE',
            `  DEACTIVATE ${outputs[0]}`
          ];
        } else {
          logic = [
            `IF condition_for_${blockName.replace(/[^a-zA-Z0-9]/g, '_')} THEN`,
            '  PERFORM required_action',
            'ELSE',
            '  MAINTAIN current_state'
          ];
        }
    }

    return {
      block: blockName,
      logic: logic
    };
  });

  return { pseudocode };
} catch(e) {
  return { error: 'Failed to generate pseudocode: ' + e.message };
}

// Extract and validate the agent's analysis results
try {
  const data = $input.first().json || {};
  const agentOutput = data.output || data;

  // Extract structured data from agent response
  let io_points = {};
  let blocks = [];
  let pseudocode = [];

  // Try to parse agent output for structured data
  if (typeof agentOutput === 'string') {
    // If agent returned text, try to extract JSON-like structures
    const ioMatch = agentOutput.match(/"io_points"\s*:\s*({[^}]+})/i);
    const blocksMatch = agentOutput.match(/"blocks"\s*:\s*(\[[^\]]+\])/i);
    const pseudocodeMatch = agentOutput.match(/"pseudocode"\s*:\s*(\[[^\]]+\])/i);

    if (ioMatch) {
      try { io_points = JSON.parse(ioMatch[1]); } catch(e) {}
    }
    if (blocksMatch) {
      try { blocks = JSON.parse(blocksMatch[1]); } catch(e) {}
    }
    if (pseudocodeMatch) {
      try { pseudocode = JSON.parse(pseudocodeMatch[1]); } catch(e) {}
    }
  } else if (typeof agentOutput === 'object') {
    // If agent returned structured data
    io_points = agentOutput.io_points || {};
    blocks = agentOutput.blocks || [];
    pseudocode = agentOutput.pseudocode || [];
  }

  // Ensure minimum structure
  if (!io_points.inputs) io_points.inputs = [];
  if (!io_points.outputs) io_points.outputs = [];
  if (!blocks.length) blocks = ['General HVAC Sequence'];
  if (!pseudocode.length) {
    pseudocode = [{
      block: blocks[0],
      logic: ['IF condition THEN action', 'ELSE maintain_state']
    }];
  }

  const sessionId = data.sessionId || 'session_' + Date.now();

  return {
    json: {
      sessionId: sessionId,
      analysis_complete: true,
      io_points: io_points,
      blocks: blocks,
      pseudocode: pseudocode,
      ready_for_review: true,
      original_text: data.extracted_text || data.text || ''
    }
  };
} catch(e) {
  return {
    json: {
      sessionId: 'error_session',
      error: 'Failed to process agent output: ' + e.message,
      analysis_complete: false
    }
  };
}

