try {
  const data = $input.first().json || {};

  // Parse stored data
  let analysisData;
  if (data.data && typeof data.data === 'string') {
    analysisData = JSON.parse(data.data);
  } else {
    analysisData = data.data || data;
  }

  if (!analysisData.io_points || !analysisData.pseudocode) {
    throw new Error('Missing required analysis data');
  }

  // Format into PyBOG schema
  const schema = {
    metadata: {
      title: 'HVAC Control Sequence',
      description: 'Generated from natural language description',
      created: new Date().toISOString(),
      sessionId: analysisData.sessionId
    },
    inputs: (analysisData.io_points.inputs || []).map((input, index) => ({
      id: `INPUT_${index + 1}`,
      name: input,
      type: 'analog', // Default to analog, can be refined
      description: `Input point: ${input}`
    })),
    outputs: (analysisData.io_points.outputs || []).map((output, index) => ({
      id: `OUTPUT_${index + 1}`,
      name: output,
      type: 'analog', // Default to analog, can be refined
      description: `Output point: ${output}`
    })),
    setpoints: [], // Can be populated from analysis if needed
    logic_blocks: (analysisData.pseudocode || []).map((block, index) => ({
      id: `BLOCK_${index + 1}`,
      name: block.block || `Block ${index + 1}`,
      description: `Control logic for ${block.block}`,
      pseudocode: Array.isArray(block.logic) ? block.logic : [block.logic || 'No logic defined'],
      priority: index + 1
    })),
    original_text: analysisData.original_text || ''
  };

  return {
    json: {
      bog_schema: schema,
      sessionId: analysisData.sessionId,
      ready_for_generation: true
    }
  };
} catch(e) {
  return {
    json: {
      error: 'Failed to format schema: ' + e.message,
      sessionId: data.sessionId || 'unknown'
    }
  };
}

try {
  const data = $input.first().json || {};
  const response = data.body || data;
  const sessionId = data.sessionId || 'unknown';

  let message = 'BOG file generated successfully!';
  let downloadUrl = null;
  let status = 'COMPLETED';

  if (data.error) {
    message = 'Error: ' + data.error;
    status = 'ERROR';
  } else if (response.success && response.download_url) {
    message = 'BOG file generated successfully! You can download it using the provided link.';
    downloadUrl = response.download_url;
  } else if (response.download_url) {
    downloadUrl = response.download_url;
  } else {
    message = 'API call completed but no download URL was provided.';
    status = 'WARNING';
  }

  return {
    json: {
      sessionId: sessionId,
      status: status,
      message: message,
      downloadUrl: downloadUrl,
      bog_generated: status === 'COMPLETED',
      timestamp: new Date().toISOString()
    }
  };
} catch(e) {
  return {
    json: {
      sessionId: data.sessionId || 'unknown',
      status: 'ERROR',
      message: 'Error processing API response: ' + e.message,
      bog_generated: false
    }
  };
}

try {
  const data = $input.first().json || {};
  const sessionId = data.sessionId || 'unknown';

  let errorMessage = 'An unknown error occurred';

  if (data.error) {
    errorMessage = data.error;
  } else if (data.message) {
    errorMessage = data.message;
  }

  return {
    json: {
      sessionId: sessionId,
      status: 'ERROR',
      message: 'Workflow failed: ' + errorMessage,
      error_details: data,
      timestamp: new Date().toISOString()
    }
  };
} catch(e) {
  return {
    json: {
      sessionId: 'unknown',
      status: 'CRITICAL_ERROR',
      message: 'Critical workflow error: ' + e.message
    }
  };
}
